'use client'
import { cn } from '@cascivo/core'
import { Children, cloneElement, isValidElement } from 'react'
import type { InputHTMLAttributes, ReactElement, ReactNode } from 'react'
import styles from './radio.module.css'

export interface RadioProps extends InputHTMLAttributes<HTMLInputElement> {
  label?: string
  value: string
}

export function Radio({ label, className, id, disabled, value, ...props }: RadioProps) {
  const radioId = id ?? (label ? `cascade-radio-${value}` : undefined)

  return (
    <label className={cn(styles['wrapper'], className)} data-disabled={disabled || undefined}>
      <input
        id={radioId}
        type="radio"
        value={value}
        className={styles['input']}
        disabled={disabled}
        {...props}
      />
      <span className={styles['control']} aria-hidden="true" />
      {label && <span className={styles['label']}>{label}</span>}
    </label>
  )
}

export interface RadioGroupProps {
  name: string
  value?: string
  defaultValue?: string
  onChange?: (value: string) => void
  orientation?: 'horizontal' | 'vertical'
  className?: string
  children: ReactNode
}

export function RadioGroup({
  name,
  value,
  defaultValue,
  onChange,
  orientation = 'vertical',
  className,
  children,
}: RadioGroupProps) {
  const isControlled = value !== undefined

  return (
    <div
      role="radiogroup"
      data-orientation={orientation}
      className={cn(styles['group'], className)}
    >
      {Children.map(children, (child) => {
        if (!isValidElement(child)) return child
        const radio = child as ReactElement<RadioProps>
        const childValue = radio.props.value
        const extra: Partial<RadioProps> = { name }

        if (isControlled) {
          extra.checked = childValue === value
        } else if (defaultValue !== undefined) {
          extra.defaultChecked = childValue === defaultValue
        }

        if (onChange) {
          extra.onChange = (event) => {
            if (event.target.checked) onChange(childValue)
          }
        }

        return cloneElement(radio, extra)
      })}
    </div>
  )
}

@layer cascivo.component {
  .group {
    display: flex;
    gap: var(--cascivo-space-3);

    &[data-orientation='vertical'] {
      flex-direction: column;
    }
    &[data-orientation='horizontal'] {
      flex-direction: row;
      flex-wrap: wrap;
    }
  }

  .wrapper {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    cursor: pointer;

    &[data-disabled] {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .input {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    margin: -1px;
    padding: 0;
    border: 0;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    overflow: hidden;
    white-space: nowrap;
  }

  .control {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    inline-size: 1.125rem;
    block-size: 1.125rem;
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border-strong);
    border-radius: var(--cascivo-radius-full);
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &::after {
      content: '';
      inline-size: 0.5rem;
      block-size: 0.5rem;
      border-radius: var(--cascivo-radius-full);
      background-color: var(--cascivo-color-text-on-accent);
      scale: 0;
      transition: scale var(--cascivo-duration-150) var(--cascivo-ease-out);
    }
  }

  .input:checked + .control {
    background-color: var(--cascivo-color-accent);
    border-color: var(--cascivo-color-accent);

    &::after {
      scale: 1;
    }
  }

  .input:focus-visible + .control {
    outline: none;
    box-shadow: var(--cascivo-focus-ring);
  }

  .label {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-snug);
  }
}

@media (forced-colors: active) {
  .control {
    border: 1px solid ButtonText;
    background-color: Field;
  }

  .input:checked + .control {
    border-color: Highlight;
    background-color: Highlight;
  }

  .input:focus-visible + .control {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}
